query:
SELECT status, platform, COUNT(*) as count FROM posts GROUP BY status, platform;
SELECT COUNT(*) as total_photos, COUNT(CASE WHEN url LIKE '%.mp4' OR url LIKE '%.mov' OR url LIKE '%.webm' THEN 1 END) as videos, COUNT(CASE WHEN url LIKE '%.jpg' OR url LIKE '%.jpeg' OR url LIKE '%.png' OR url LIKE '%.webp' THEN 1 END) as images FROM food_photos;
SELECT id, url, caption, menu_item_id, created_at FROM food_photos ORDER BY created_at DESC LIMIT 20;

